import React, { useState, useEffect } from 'react';
import { Card, Row, Col, Table, Badge, ProgressBar, Alert } from 'react-bootstrap';
import { 
  FileText, 
  Users, 
  Store, 
  CheckCircle, 
  XCircle, 
  AlertTriangle, 
  TrendingUp,
  AlertCircle,
  Clock,
  Target
} from 'lucide-react';
import { searchDocuments } from '../api';
import './ComplianceDashboard.css';

const ComplianceDashboard = () => {
  const [loading, setLoading] = useState(true);
  const [dashboardData, setDashboardData] = useState({
    totalDocuments: 0,
    validDocuments: 0,
    expiringDocuments: 0,
    expiredDocuments: 0,
    missingDocuments: 0,
    totalEmployees: 20,
    employeesWithCompleteDocuments: 0,
    employeesWithPendingDocuments: 0,
    storeWiseData: [],
    employeeWiseData: [],
    complianceRate: 0
  });

  // Employee-Store mapping
  const employeeStoreMapping = [
    { id: 'EMP001', name: 'Rajesh Kumar', store: 'Store 1' },
    { id: 'EMP002', name: 'Priya Singh', store: 'Store 2' },
    { id: 'EMP003', name: 'Amit Patel', store: 'Store 3' },
    { id: 'EMP004', name: 'Sneha Reddy', store: 'Store 4' },
    { id: 'EMP005', name: 'Vikram Sharma', store: 'Store 5' },
    { id: 'EMP006', name: 'Anita Desai', store: 'Store 6' },
    { id: 'EMP007', name: 'Rahul Mehta', store: 'Store 7' },
    { id: 'EMP008', name: 'Kavita Joshi', store: 'Store 8' },
    { id: 'EMP009', name: 'Suresh Nair', store: 'Store 9' },
    { id: 'EMP010', name: 'Meera Nair', store: 'Store 10' },
    { id: 'EMP011', name: 'Arjun Verma', store: 'Store 11' },
    { id: 'EMP012', name: 'Deepika Rao', store: 'Store 12' },
    { id: 'EMP013', name: 'Karan Malhotra', store: 'Store 13' },
    { id: 'EMP014', name: 'Pooja Gupta', store: 'Store 14' },
    { id: 'EMP015', name: 'Sanjay Iyer', store: 'Store 15' },
    { id: 'EMP016', name: 'Ritu Kapoor', store: 'Store 16' },
    { id: 'EMP017', name: 'Anil Chatterjee', store: 'Store 17' },
    { id: 'EMP018', name: 'Swati Bose', store: 'Store 18' },
    { id: 'EMP019', name: 'Manoj Pillai', store: 'Store 19' },
    { id: 'EMP020', name: 'Nisha Agarwal', store: 'Store 20' }
  ];

  // Mandatory document types
  const mandatoryDocuments = [
    'ID Proof',
    'Address Proof',
    'Educational Certificate',
    'Employment Contract'
  ];

  useEffect(() => {
    loadDashboardData();
  }, []);

  const getStatusColor = (expiryDate) => {
    if (!expiryDate) return 'valid';
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    const expiry = new Date(expiryDate);
    expiry.setHours(0, 0, 0, 0);
    const daysUntilExpiry = Math.floor((expiry - today) / (1000 * 60 * 60 * 24));
    
    if (daysUntilExpiry <= 0) return 'expired';
    if (daysUntilExpiry <= 30) return 'expiring';
    return 'valid';
  };

  const loadDashboardData = async () => {
    setLoading(true);
    try {
      const response = await searchDocuments({});
      if (response.data && response.data.data) {
        const documents = response.data.data.map(doc => {
          const employee = employeeStoreMapping.find(emp => emp.id === doc.employeeId);
          return {
            ...doc,
            store: doc.store || (employee ? employee.store : 'Unknown'),
            employeeName: doc.employeeName || (employee ? employee.name : 'Unknown'),
            status: getStatusColor(doc.expiryDate)
          };
        });

        // Calculate statistics
        const totalDocuments = documents.length;
        const validDocuments = documents.filter(doc => doc.status === 'valid').length;
        const expiringDocuments = documents.filter(doc => doc.status === 'expiring').length;
        const expiredDocuments = documents.filter(doc => doc.status === 'expired').length;

        // Calculate employee-wise data
        const employeeDocCounts = {};
        documents.forEach(doc => {
          if (!employeeDocCounts[doc.employeeId]) {
            const emp = employeeStoreMapping.find(e => e.id === doc.employeeId);
            employeeDocCounts[doc.employeeId] = {
              employeeId: doc.employeeId,
              employeeName: emp ? emp.name : 'Unknown',
              store: emp ? emp.store : 'Unknown',
              totalDocs: 0,
              validDocs: 0,
              expiredDocs: 0,
              expiringDocs: 0,
              mandatoryDocs: [],
              missingMandatory: []
            };
          }
          employeeDocCounts[doc.employeeId].totalDocs++;
          if (doc.status === 'valid') employeeDocCounts[doc.employeeId].validDocs++;
          if (doc.status === 'expired') employeeDocCounts[doc.employeeId].expiredDocs++;
          if (doc.status === 'expiring') employeeDocCounts[doc.employeeId].expiringDocs++;
          
          if (mandatoryDocuments.includes(doc.documentType)) {
            employeeDocCounts[doc.employeeId].mandatoryDocs.push(doc.documentType);
          }
        });

        // Calculate missing mandatory documents
        let totalMissingDocs = 0;
        Object.keys(employeeDocCounts).forEach(empId => {
          const missing = mandatoryDocuments.filter(
            docType => !employeeDocCounts[empId].mandatoryDocs.includes(docType)
          );
          employeeDocCounts[empId].missingMandatory = missing;
          totalMissingDocs += missing.length;
        });

        // Add employees with no documents
        employeeStoreMapping.forEach(emp => {
          if (!employeeDocCounts[emp.id]) {
            employeeDocCounts[emp.id] = {
              employeeId: emp.id,
              employeeName: emp.name,
              store: emp.store,
              totalDocs: 0,
              validDocs: 0,
              expiredDocs: 0,
              expiringDocs: 0,
              mandatoryDocs: [],
              missingMandatory: mandatoryDocuments
            };
            totalMissingDocs += mandatoryDocuments.length;
          }
        });

        const employeeWiseData = Object.values(employeeDocCounts);
        const employeesWithCompleteDocuments = employeeWiseData.filter(
          emp => emp.missingMandatory.length === 0 && emp.expiredDocs === 0
        ).length;
        const employeesWithPendingDocuments = employeeStoreMapping.length - employeesWithCompleteDocuments;

        // Calculate store-wise data
        const storeDocCounts = {};
        documents.forEach(doc => {
          if (!storeDocCounts[doc.store]) {
            storeDocCounts[doc.store] = {
              store: doc.store,
              totalDocs: 0,
              validDocs: 0,
              expiredDocs: 0,
              expiringDocs: 0,
              employees: new Set()
            };
          }
          storeDocCounts[doc.store].totalDocs++;
          if (doc.status === 'valid') storeDocCounts[doc.store].validDocs++;
          if (doc.status === 'expired') storeDocCounts[doc.store].expiredDocs++;
          if (doc.status === 'expiring') storeDocCounts[doc.store].expiringDocs++;
          storeDocCounts[doc.store].employees.add(doc.employeeId);
        });

        const storeWiseData = Object.values(storeDocCounts).map(store => ({
          ...store,
          employeeCount: store.employees.size,
          complianceRate: store.totalDocs > 0 
            ? Math.round((store.validDocs / store.totalDocs) * 100) 
            : 0
        }));

        // Sort by store name
        storeWiseData.sort((a, b) => {
          const numA = parseInt(a.store.replace('Store ', ''));
          const numB = parseInt(b.store.replace('Store ', ''));
          return numA - numB;
        });

        const complianceRate = totalDocuments > 0 
          ? Math.round((validDocuments / totalDocuments) * 100) 
          : 0;

        setDashboardData({
          totalDocuments,
          validDocuments,
          expiringDocuments,
          expiredDocuments,
          missingDocuments: totalMissingDocs,
          totalEmployees: employeeStoreMapping.length,
          employeesWithCompleteDocuments,
          employeesWithPendingDocuments,
          storeWiseData,
          employeeWiseData,
          complianceRate
        });
      }
    } catch (error) {
      console.error('Error loading dashboard data:', error);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <div className="text-center py-5">
        <div className="spinner-border text-primary" role="status">
          <span className="visually-hidden">Loading...</span>
        </div>
        <p className="mt-3 text-muted">Loading compliance dashboard...</p>
      </div>
    );
  }

  return (
    <div className="compliance-dashboard">
      {/* Header */}
      <Card className="mb-4 border-0 shadow-sm">
        <Card.Header className="bg-gradient-primary text-white">
          <h3 className="mb-1">
            <Target className="me-2" size={28} />
            Overall Compliance Dashboard
          </h3>
          <p className="mb-0 opacity-75">Real-time document compliance monitoring and analytics</p>
        </Card.Header>
      </Card>

      {/* Alert Banners */}
      {dashboardData.expiredDocuments > 0 && (
        <Alert variant="danger" className="mb-4">
          <XCircle className="me-2" size={20} />
          <strong>Critical:</strong> {dashboardData.expiredDocuments} document(s) have expired and require immediate renewal.
        </Alert>
      )}

      {dashboardData.missingDocuments > 0 && (
        <Alert variant="warning" className="mb-4">
          <AlertTriangle className="me-2" size={20} />
          <strong>Action Required:</strong> {dashboardData.missingDocuments} mandatory document(s) are missing across {dashboardData.employeesWithPendingDocuments} employee(s).
        </Alert>
      )}

      {/* Main Statistics Cards */}
      <Row className="mb-4">
        <Col md={3}>
          <Card className="stats-card border-0 shadow-sm h-100">
            <Card.Body>
              <div className="d-flex justify-content-between align-items-start">
                <div>
                  <div className="text-muted small mb-1">TOTAL DOCUMENTS</div>
                  <h2 className="mb-0 fw-bold text-primary">{dashboardData.totalDocuments}</h2>
                </div>
                <div className="stats-icon bg-primary">
                  <FileText size={24} />
                </div>
              </div>
              <div className="mt-3">
                <small className="text-muted">All uploaded documents</small>
              </div>
            </Card.Body>
          </Card>
        </Col>

        <Col md={3}>
          <Card className="stats-card border-0 shadow-sm h-100">
            <Card.Body>
              <div className="d-flex justify-content-between align-items-start">
                <div>
                  <div className="text-muted small mb-1">VALID DOCUMENTS</div>
                  <h2 className="mb-0 fw-bold text-success">{dashboardData.validDocuments}</h2>
                </div>
                <div className="stats-icon bg-success">
                  <CheckCircle size={24} />
                </div>
              </div>
              <div className="mt-3">
                <small className="text-success">
                  {dashboardData.complianceRate}% compliance rate
                </small>
              </div>
            </Card.Body>
          </Card>
        </Col>

        <Col md={3}>
          <Card className="stats-card border-0 shadow-sm h-100">
            <Card.Body>
              <div className="d-flex justify-content-between align-items-start">
                <div>
                  <div className="text-muted small mb-1">EXPIRING SOON</div>
                  <h2 className="mb-0 fw-bold text-warning">{dashboardData.expiringDocuments}</h2>
                </div>
                <div className="stats-icon bg-warning">
                  <Clock size={24} />
                </div>
              </div>
              <div className="mt-3">
                <small className="text-warning">Within 30 days</small>
              </div>
            </Card.Body>
          </Card>
        </Col>

        <Col md={3}>
          <Card className="stats-card border-0 shadow-sm h-100">
            <Card.Body>
              <div className="d-flex justify-content-between align-items-start">
                <div>
                  <div className="text-muted small mb-1">EXPIRED</div>
                  <h2 className="mb-0 fw-bold text-danger">{dashboardData.expiredDocuments}</h2>
                </div>
                <div className="stats-icon bg-danger">
                  <XCircle size={24} />
                </div>
              </div>
              <div className="mt-3">
                <small className="text-danger">Requires renewal</small>
              </div>
            </Card.Body>
          </Card>
        </Col>
      </Row>

      {/* Employee & Missing Documents Statistics */}
      <Row className="mb-4">
        <Col md={4}>
          <Card className="stats-card border-0 shadow-sm h-100">
            <Card.Body>
              <div className="d-flex justify-content-between align-items-start">
                <div>
                  <div className="text-muted small mb-1">TOTAL EMPLOYEES</div>
                  <h2 className="mb-0 fw-bold text-info">{dashboardData.totalEmployees}</h2>
                </div>
                <div className="stats-icon bg-info">
                  <Users size={24} />
                </div>
              </div>
              <div className="mt-3">
                <small className="text-muted">Active employees</small>
              </div>
            </Card.Body>
          </Card>
        </Col>

        <Col md={4}>
          <Card className="stats-card border-0 shadow-sm h-100">
            <Card.Body>
              <div className="d-flex justify-content-between align-items-start">
                <div>
                  <div className="text-muted small mb-1">COMPLETE COMPLIANCE</div>
                  <h2 className="mb-0 fw-bold text-success">{dashboardData.employeesWithCompleteDocuments}</h2>
                </div>
                <div className="stats-icon bg-success">
                  <CheckCircle size={24} />
                </div>
              </div>
              <div className="mt-3">
                <small className="text-success">
                  {Math.round((dashboardData.employeesWithCompleteDocuments / dashboardData.totalEmployees) * 100)}% employees
                </small>
              </div>
            </Card.Body>
          </Card>
        </Col>

        <Col md={4}>
          <Card className="stats-card border-0 shadow-sm h-100">
            <Card.Body>
              <div className="d-flex justify-content-between align-items-start">
                <div>
                  <div className="text-muted small mb-1">MISSING DOCUMENTS</div>
                  <h2 className="mb-0 fw-bold text-danger">{dashboardData.missingDocuments}</h2>
                </div>
                <div className="stats-icon bg-danger">
                  <AlertCircle size={24} />
                </div>
              </div>
              <div className="mt-3">
                <small className="text-danger">
                  {dashboardData.employeesWithPendingDocuments} employees affected
                </small>
              </div>
            </Card.Body>
          </Card>
        </Col>
      </Row>

      {/* Overall Compliance Progress */}
      <Card className="mb-4 border-0 shadow-sm">
        <Card.Header className="bg-white border-bottom">
          <h5 className="mb-0">
            <TrendingUp className="me-2" size={20} />
            Overall Compliance Rate
          </h5>
        </Card.Header>
        <Card.Body>
          <div className="mb-2 d-flex justify-content-between">
            <span className="fw-bold">Document Compliance</span>
            <span className="fw-bold">{dashboardData.complianceRate}%</span>
          </div>
          <ProgressBar 
            now={dashboardData.complianceRate} 
            variant={dashboardData.complianceRate >= 80 ? 'success' : dashboardData.complianceRate >= 50 ? 'warning' : 'danger'}
            style={{ height: '30px' }}
            label={`${dashboardData.complianceRate}%`}
          />
          <div className="mt-3">
            <Row>
              <Col md={3}>
                <div className="text-center">
                  <div className="text-success fw-bold h4">{dashboardData.validDocuments}</div>
                  <div className="text-muted small">Valid</div>
                </div>
              </Col>
              <Col md={3}>
                <div className="text-center">
                  <div className="text-warning fw-bold h4">{dashboardData.expiringDocuments}</div>
                  <div className="text-muted small">Expiring</div>
                </div>
              </Col>
              <Col md={3}>
                <div className="text-center">
                  <div className="text-danger fw-bold h4">{dashboardData.expiredDocuments}</div>
                  <div className="text-muted small">Expired</div>
                </div>
              </Col>
              <Col md={3}>
                <div className="text-center">
                  <div className="text-secondary fw-bold h4">{dashboardData.missingDocuments}</div>
                  <div className="text-muted small">Missing</div>
                </div>
              </Col>
            </Row>
          </div>
        </Card.Body>
      </Card>

      {/* Store-wise Summary */}
      <Card className="mb-4 border-0 shadow-sm">
        <Card.Header className="bg-white border-bottom">
          <h5 className="mb-0">
            <Store className="me-2" size={20} />
            Store-wise Document Summary
          </h5>
        </Card.Header>
        <Card.Body>
          <div className="table-responsive">
            <Table hover className="compliance-table">
              <thead>
                <tr>
                  <th>Store</th>
                  <th className="text-center">Employees</th>
                  <th className="text-center">Total Docs</th>
                  <th className="text-center">Valid</th>
                  <th className="text-center">Expiring</th>
                  <th className="text-center">Expired</th>
                  <th className="text-center">Compliance</th>
                </tr>
              </thead>
              <tbody>
                {dashboardData.storeWiseData.length === 0 ? (
                  <tr>
                    <td colSpan="7" className="text-center text-muted py-4">
                      No store data available
                    </td>
                  </tr>
                ) : (
                  dashboardData.storeWiseData.map((store, idx) => (
                    <tr key={idx}>
                      <td>
                        <strong>{store.store}</strong>
                      </td>
                      <td className="text-center">
                        <Badge bg="secondary">{store.employeeCount}</Badge>
                      </td>
                      <td className="text-center">{store.totalDocs}</td>
                      <td className="text-center">
                        <Badge bg="success">{store.validDocs}</Badge>
                      </td>
                      <td className="text-center">
                        <Badge bg="warning">{store.expiringDocs}</Badge>
                      </td>
                      <td className="text-center">
                        <Badge bg="danger">{store.expiredDocs}</Badge>
                      </td>
                      <td className="text-center">
                        <div className="d-flex align-items-center justify-content-center">
                          <ProgressBar 
                            now={store.complianceRate} 
                            variant={store.complianceRate >= 80 ? 'success' : store.complianceRate >= 50 ? 'warning' : 'danger'}
                            style={{ width: '100px', height: '20px' }}
                            label={`${store.complianceRate}%`}
                          />
                        </div>
                      </td>
                    </tr>
                  ))
                )}
              </tbody>
            </Table>
          </div>
        </Card.Body>
      </Card>

      {/* Employee-wise Compliance */}
      <Card className="border-0 shadow-sm">
        <Card.Header className="bg-white border-bottom">
          <h5 className="mb-0">
            <Users className="me-2" size={20} />
            Employee-wise Document Status
          </h5>
        </Card.Header>
        <Card.Body>
          <div className="table-responsive">
            <Table hover className="compliance-table">
              <thead>
                <tr>
                  <th>Employee</th>
                  <th>Store</th>
                  <th className="text-center">Total Docs</th>
                  <th className="text-center">Valid</th>
                  <th className="text-center">Expiring</th>
                  <th className="text-center">Expired</th>
                  <th className="text-center">Missing Mandatory</th>
                  <th className="text-center">Status</th>
                </tr>
              </thead>
              <tbody>
                {dashboardData.employeeWiseData
                  .sort((a, b) => b.missingMandatory.length - a.missingMandatory.length)
                  .map((emp, idx) => {
                    const isCompliant = emp.missingMandatory.length === 0 && emp.expiredDocs === 0;
                    return (
                      <tr key={idx}>
                        <td>
                          <div>
                            <strong>{emp.employeeName}</strong>
                            <br />
                            <small className="text-muted">{emp.employeeId}</small>
                          </div>
                        </td>
                        <td>
                          <Badge bg="secondary">{emp.store}</Badge>
                        </td>
                        <td className="text-center">{emp.totalDocs}</td>
                        <td className="text-center">
                          <Badge bg="success">{emp.validDocs}</Badge>
                        </td>
                        <td className="text-center">
                          <Badge bg="warning">{emp.expiringDocs}</Badge>
                        </td>
                        <td className="text-center">
                          <Badge bg="danger">{emp.expiredDocs}</Badge>
                        </td>
                        <td className="text-center">
                          {emp.missingMandatory.length > 0 ? (
                            <Badge bg="danger" title={emp.missingMandatory.join(', ')}>
                              {emp.missingMandatory.length}
                            </Badge>
                          ) : (
                            <Badge bg="success">0</Badge>
                          )}
                        </td>
                        <td className="text-center">
                          {isCompliant ? (
                            <Badge bg="success">
                              <CheckCircle size={14} className="me-1" />
                              Compliant
                            </Badge>
                          ) : (
                            <Badge bg="warning">
                              <AlertTriangle size={14} className="me-1" />
                              Pending
                            </Badge>
                          )}
                        </td>
                      </tr>
                    );
                  })}
              </tbody>
            </Table>
          </div>
        </Card.Body>
      </Card>
    </div>
  );
};

export default ComplianceDashboard;
